+      microLoraRank: 2,
+      baseLoraRank: 16,
+      patternClusters: 200,
+    },
+  });
+}
+
+/**
+ * Create a lightweight engine for fast startup
+ */
+export function createLightweightEngine(): IntelligenceEngine {
+  return new IntelligenceEngine({
+    embeddingDim: 128,
+    maxMemories: 10000,
+    maxEpisodes: 5000,
+    enableSona: false,
+    enableAttention: false,
+  });
+}
+
+export default IntelligenceEngine;
